(window.webpackJsonp=window.webpackJsonp||[]).push([[538],{551:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{string}</span> <span class=\\"hljs-variable\\">expression</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{string[]}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> braceExpansionII = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">expression</span>) </span>{\\n  <span class=\\"hljs-keyword\\">return</span> resolve(expression).sort()\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">resolve</span>(<span class=\\"hljs-params\\">exp</span>)</span>{\\n    <span class=\\"hljs-keyword\\">if</span>(<span class=\\"hljs-built_in\\">Array</span>.isArray(exp))<span class=\\"hljs-keyword\\">return</span> exp\\n    <span class=\\"hljs-keyword\\">let</span> str=<span class=\\"hljs-string\\">\'\'</span>,group=[],arr=[]\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;exp.length;i++){\\n      <span class=\\"hljs-keyword\\">if</span>(exp[i]===<span class=\\"hljs-string\\">\'{\'</span>){\\n        <span class=\\"hljs-keyword\\">if</span>(str!==<span class=\\"hljs-string\\">\'\'</span>){\\n          arr=multi(arr,[str])\\n          str=<span class=\\"hljs-string\\">\'\'</span>\\n        }\\n        <span class=\\"hljs-keyword\\">let</span> prev=resolve(arr)\\n        <span class=\\"hljs-keyword\\">let</span> [sub,nxtId]=findSub(exp,i+<span class=\\"hljs-number\\">1</span>)\\n        <span class=\\"hljs-keyword\\">let</span> r_sub=resolve(sub)\\n        arr=multi(prev,r_sub)\\n        i=nxtId\\n      }<span class=\\"hljs-keyword\\">else</span> <span class=\\"hljs-keyword\\">if</span>(exp[i]===<span class=\\"hljs-string\\">\',\'</span>){\\n         <span class=\\"hljs-keyword\\">if</span>(str!==<span class=\\"hljs-string\\">\'\'</span>){\\n          arr=multi(arr,[str])\\n          str=<span class=\\"hljs-string\\">\'\'</span>\\n        }\\n        group.push(resolve(arr))\\n        arr=[]\\n      }<span class=\\"hljs-keyword\\">else</span>{\\n        str+=exp[i]\\n      }\\n    }\\n    <span class=\\"hljs-keyword\\">if</span>(str!==<span class=\\"hljs-string\\">\'\'</span>){\\n      <span class=\\"hljs-comment\\">// group.push([str])</span>\\n      arr=multi(arr,[str])\\n    }\\n    <span class=\\"hljs-keyword\\">if</span>(arr.length&gt;<span class=\\"hljs-number\\">0</span>){\\n      group.push(arr)\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> add(group)\\n  }\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">multi</span>(<span class=\\"hljs-params\\">r1,r2</span>)</span>{\\n    <span class=\\"hljs-keyword\\">if</span>(r1.length===<span class=\\"hljs-number\\">0</span>)<span class=\\"hljs-keyword\\">return</span> r2\\n    <span class=\\"hljs-keyword\\">if</span>(r2.length===<span class=\\"hljs-number\\">0</span>)<span class=\\"hljs-keyword\\">return</span> r1\\n    <span class=\\"hljs-keyword\\">let</span> res=[],hash={}\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;r1.length;i++){\\n      <span class=\\"hljs-keyword\\">if</span>(<span class=\\"hljs-regexp\\">/[\\\\{\\\\}\\\\,]/</span>.test(r1[i]))<span class=\\"hljs-keyword\\">continue</span>\\n      <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> j=<span class=\\"hljs-number\\">0</span>;j&lt;r2.length;j++){\\n        <span class=\\"hljs-keyword\\">if</span>(<span class=\\"hljs-regexp\\">/[\\\\{\\\\}\\\\,]/</span>.test(r2[j]))<span class=\\"hljs-keyword\\">continue</span>\\n        <span class=\\"hljs-keyword\\">let</span> cur=r1[i]+r2[j]    \\n        <span class=\\"hljs-keyword\\">if</span>(hash[cur])<span class=\\"hljs-keyword\\">continue</span>\\n        hash[cur]=<span class=\\"hljs-literal\\">true</span>\\n        res.push(cur)\\n      }\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> res\\n  }\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">add</span>(<span class=\\"hljs-params\\">arr</span>)</span>{\\n    <span class=\\"hljs-keyword\\">let</span> res=[]\\n    <span class=\\"hljs-keyword\\">let</span> hash={}\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;arr.length;i++){\\n      <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> j=<span class=\\"hljs-number\\">0</span>;j&lt;arr[i].length;j++){\\n        <span class=\\"hljs-keyword\\">if</span>(<span class=\\"hljs-regexp\\">/[\\\\{\\\\}\\\\,]/</span>.test(arr[i][j]))<span class=\\"hljs-keyword\\">continue</span>\\n        <span class=\\"hljs-keyword\\">if</span>(hash[arr[i][j]])<span class=\\"hljs-keyword\\">continue</span>\\n        hash[arr[i][j]]=<span class=\\"hljs-literal\\">true</span>\\n        res.push(arr[i][j])\\n      }\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> res\\n  }\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">findSub</span>(<span class=\\"hljs-params\\">exp,id</span>)</span>{\\n    <span class=\\"hljs-keyword\\">let</span> count=<span class=\\"hljs-number\\">1</span>\\n    <span class=\\"hljs-keyword\\">let</span> str=<span class=\\"hljs-string\\">\'\'</span>\\n    <span class=\\"hljs-keyword\\">while</span>(<span class=\\"hljs-literal\\">true</span>){\\n      <span class=\\"hljs-keyword\\">if</span>(exp[id]===<span class=\\"hljs-string\\">\'{\'</span>){\\n        count++\\n      }<span class=\\"hljs-keyword\\">else</span> <span class=\\"hljs-keyword\\">if</span>(exp[id]===<span class=\\"hljs-string\\">\'}\'</span>){\\n        count--\\n      }\\n      <span class=\\"hljs-keyword\\">if</span>(count===<span class=\\"hljs-number\\">0</span>)<span class=\\"hljs-keyword\\">return</span> [str,id]\\n      str+=exp[id]\\n      id++\\n    }\\n  }\\n\\n};\\n</code></pre>\\n"],"titleSlug":"brace-expansion-ii","hasThinking":false,"content":"<p>\u5982\u679c\u4f60\u719f\u6089 Shell \u7f16\u7a0b\uff0c\u90a3\u4e48\u4e00\u5b9a\u4e86\u89e3\u8fc7\u82b1\u62ec\u53f7\u5c55\u5f00\uff0c\u5b83\u53ef\u4ee5\u7528\u6765\u751f\u6210\u4efb\u610f\u5b57\u7b26\u4e32\u3002</p>\\n\\n<p>\u82b1\u62ec\u53f7\u5c55\u5f00\u7684\u8868\u8fbe\u5f0f\u53ef\u4ee5\u770b\u4f5c\u4e00\u4e2a\u7531 <strong>\u82b1\u62ec\u53f7</strong>\u3001<strong>\u9017\u53f7</strong> \u548c <strong>\u5c0f\u5199\u82f1\u6587\u5b57\u6bcd</strong> \u7ec4\u6210\u7684\u5b57\u7b26\u4e32\uff0c\u5b9a\u4e49\u4e0b\u9762\u51e0\u6761\u8bed\u6cd5\u89c4\u5219\uff1a</p>\\n\\n<ul>\\n\\t<li>\u5982\u679c\u53ea\u7ed9\u51fa\u5355\u4e00\u7684\u5143\u7d20\xa0<code>x</code>\uff0c\u90a3\u4e48\u8868\u8fbe\u5f0f\u8868\u793a\u7684\u5b57\u7b26\u4e32\u5c31\u53ea\u6709\xa0<code>\\"x\\"</code>\u3002<code>R(x) = {x}</code>\\n\\n\\t<ul>\\n\\t\\t<li>\u4f8b\u5982\uff0c\u8868\u8fbe\u5f0f <code>{\\"a\\"}</code>\xa0\u8868\u793a\u5b57\u7b26\u4e32 <code>\\"a\\"</code>\u3002</li>\\n\\t\\t<li>\u800c\u8868\u8fbe\u5f0f <code>{\\"w\\"}</code>\xa0\u5c31\u8868\u793a\u5b57\u7b26\u4e32 <code>\\"w\\"</code>\u3002</li>\\n\\t</ul>\\n\\t</li>\\n\\t<li>\u5f53\u4e24\u4e2a\u6216\u591a\u4e2a\u8868\u8fbe\u5f0f\u5e76\u5217\uff0c\u4ee5\u9017\u53f7\u5206\u9694\u65f6\uff0c\u6211\u4eec\u53d6\u8fd9\u4e9b\u8868\u8fbe\u5f0f\u4e2d\u5143\u7d20\u7684\u5e76\u96c6\u3002<code>R({e_1,e_2,...}) = R(e_1)\xa0\u222a R(e_2)\xa0\u222a ...</code>\\n\\t<ul>\\n\\t\\t<li>\u4f8b\u5982\uff0c\u8868\u8fbe\u5f0f <code>\\"{a,b,c}\\"</code> \u8868\u793a\u5b57\u7b26\u4e32\xa0<code>\\"a\\",\\"b\\",\\"c\\"</code>\u3002</li>\\n\\t\\t<li>\u800c\u8868\u8fbe\u5f0f <code>\\"{{a,b},{b,c}}\\"</code> \u4e5f\u53ef\u4ee5\u8868\u793a\u5b57\u7b26\u4e32\xa0<code>\\"a\\",\\"b\\",\\"c\\"</code>\u3002</li>\\n\\t</ul>\\n\\t</li>\\n\\t<li>\u8981\u662f\u4e24\u4e2a\u6216\u591a\u4e2a\u8868\u8fbe\u5f0f\u76f8\u63a5\uff0c\u4e2d\u95f4\u6ca1\u6709\u9694\u5f00\u65f6\uff0c\u6211\u4eec\u4ece\u8fd9\u4e9b\u8868\u8fbe\u5f0f\u4e2d\u5404\u53d6\u4e00\u4e2a\u5143\u7d20\u4f9d\u6b21\u8fde\u63a5\u5f62\u6210\u5b57\u7b26\u4e32\u3002<code>R(e_1 + e_2) = {a + b for (a, b) in\xa0R(e_1)\xa0\xd7 R(e_2)}</code>\\n\\t<ul>\\n\\t\\t<li>\u4f8b\u5982\uff0c\u8868\u8fbe\u5f0f <code>\\"{a,b}{c,d}\\"</code> \u8868\u793a\u5b57\u7b26\u4e32\xa0<code>\\"ac\\",\\"ad\\",\\"bc\\",\\"bd\\"</code>\u3002</li>\\n\\t</ul>\\n\\t</li>\\n\\t<li>\u8868\u8fbe\u5f0f\u4e4b\u95f4\u5141\u8bb8\u5d4c\u5957\uff0c\u5355\u4e00\u5143\u7d20\u4e0e\u8868\u8fbe\u5f0f\u7684\u8fde\u63a5\u4e5f\u662f\u5141\u8bb8\u7684\u3002\\n\\t<ul>\\n\\t\\t<li>\u4f8b\u5982\uff0c\u8868\u8fbe\u5f0f <code>\\"a{b,c,d}\\"</code> \u8868\u793a\u5b57\u7b26\u4e32\xa0<code>\\"ab\\",\\"ac\\",\\"ad\\"\u200b\u200b\u200b\u200b\u200b\u200b</code>\u3002</li>\\n\\t\\t<li>\u4f8b\u5982\uff0c\u8868\u8fbe\u5f0f <code>\\"a{b,c}{d,e}f{g,h}\\"</code> \u53ef\u4ee5\u8868\u793a\u5b57\u7b26\u4e32\xa0<code>\\"abdfg\\", \\"abdfh\\", \\"abefg\\", \\"abefh\\", \\"acdfg\\", \\"acdfh\\", \\"acefg\\", \\"acefh\\"</code>\u3002</li>\\n\\t</ul>\\n\\t</li>\\n</ul>\\n\\n<p>\u7ed9\u51fa\u8868\u793a\u57fa\u4e8e\u7ed9\u5b9a\u8bed\u6cd5\u89c4\u5219\u7684\u8868\u8fbe\u5f0f\xa0<code>expression</code>\uff0c\u8fd4\u56de\u5b83\u6240\u8868\u793a\u7684\u6240\u6709\u5b57\u7b26\u4e32\u7ec4\u6210\u7684\u6709\u5e8f\u5217\u8868\u3002</p>\\n\\n<p>\u5047\u5982\u4f60\u5e0c\u671b\u4ee5\u300c\u96c6\u5408\u300d\u7684\u6982\u5ff5\u4e86\u89e3\u6b64\u9898\uff0c\u4e5f\u53ef\u4ee5\u901a\u8fc7\u70b9\u51fb \u201c<strong>\u663e\u793a\u82f1\u6587\u63cf\u8ff0</strong>\u201d \u83b7\u53d6\u8be6\u60c5\u3002</p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>\\"{a,b}{c,{d,e}}\\"\\n<strong>\u8f93\u51fa\uff1a</strong>[\\"ac\\",\\"ad\\",\\"ae\\",\\"bc\\",\\"bd\\",\\"be\\"]</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>\\"{{a,z},a{b,c},{ab,z}}\\"\\n<strong>\u8f93\u51fa\uff1a</strong>[\\"a\\",\\"ab\\",\\"ac\\",\\"z\\"]\\n<strong>\u89e3\u91ca\uff1a</strong>\u8f93\u51fa\u4e2d <strong>\u4e0d\u5e94 </strong>\u51fa\u73b0\u91cd\u590d\u7684\u7ec4\u5408\u7ed3\u679c\u3002\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ol>\\n\\t<li><code>1 <= expression.length <= 50</code></li>\\n\\t<li><code>expression[i]</code> \u7531 <code>\'{\'</code>\uff0c<code>\'}\'</code>\uff0c<code>\',\'</code>\xa0\u6216\u5c0f\u5199\u82f1\u6587\u5b57\u6bcd\u7ec4\u6210</li>\\n\\t<li>\u7ed9\u51fa\u7684\u8868\u8fbe\u5f0f\xa0<code>expression</code>\xa0\u7528\u4ee5\u8868\u793a\u4e00\u7ec4\u57fa\u4e8e\u9898\u76ee\u63cf\u8ff0\u4e2d\u8bed\u6cd5\u6784\u9020\u7684\u5b57\u7b26\u4e32</li>\\n</ol>\\n","title":"1096. \u82b1\u62ec\u53f7\u5c55\u5f00 II","relatedTags":["\u5b57\u7b26\u4e32"],"difficult":"Hard","lang":["javascript"],"uniqueID":"1096"}')}}]);